<script lang="ts" setup>
import { showDialog } from 'vant';

const props = defineProps({
  modelValue: {
    type: Boolean, // 类型为布尔值
    default: false, // 默认值为 false
  },
  title: {
    type: String,
    default: '',
  },
  desc: {
    type: String,
    default: '',
  },
  link: {
    type: String,
    default: '',
  },
  imgUrl: {
    type: String,
    default: '',
  },
});

// 定义组件的 emits
const emit = defineEmits(['update:modelValue']); // 定义一个事件，用于更新父组件的绑定值

// 响应式变量，用于控制弹窗的显示状态
const visible = ref(props.modelValue);

// 监听 props 中的 modelValue 变化，同步到 visible
watch(
  () => props.modelValue,
  (newValue) => {
    visible.value = newValue;
  }
);

watch(
  () => visible.value,
  (newValue, oldValue) => {
    if (newValue !== oldValue) {
      emit('update:modelValue', newValue); // 发送事件更新父组件的绑定值
    }
  }
);

// 分享到企业微信聊天窗
const shareWechatMessage = () => {
  console.log('shareWechatMessage :>> ', {
    title: props.title,
    desc: props.desc,
    link: props.link,
    imgUrl: props.imgUrl,
  });
  (window as any).$qywx.shareWechatMessage(
    {
      title: props.title,
      desc: props.desc,
      link: props.link,
      imgUrl: props.imgUrl,
    },
    (object) => {
      console.log('shareWechatMessage :>> ', object);
      visible.value = false;
    }
  );
};
// 分享到微信朋友圈功能
const onMenuShareTimeline = () => {
  console.log('onMenuShareTimeline :>> ', {
    title: props.title,
    link: props.link,
    imgUrl: props.imgUrl,
  });
  (window as any).$qywx.onMenuShareTimeline(
    {
      title: props.title,
      link: props.link,
      imgUrl: props.imgUrl,
    },
    (object) => {
      console.log('onMenuShareTimeline :>> ', object);
    }
  );
  showDialog({ message: '分享内容已经准备好了，请点击右上角进行朋友圈分享' });
  visible.value = false;
};

const shareToExternalMoments = () => {
  (window as any).$qywx.shareToExternalMoments(
    { title: props.title, desc: props.desc, link: props.link, imgUrl: props.imgUrl },
    (object) => {
      console.log('shareToExternalMoments :>> ', object);
      visible.value = false;
    }
  );
};
</script>

